export interface Course {
  code: string;
  name_en: string;
  name_ar: string;
  credits: number;
  year?: number;
  semester?: number;
  term?: string;
  type?: "Required" | "Elective" | string;
  program_ids?: string[];
}

export interface Program {
  id: string;
  name_en: string;
  name_ar: string;
  degree: string;
}

export interface Department {
  id: string;
  name_ar: string;
  name_en: string;
  degrees: string[];
  programs?: Program[];
  courses: Course[];
}

export interface College {
  id: string;
  name_ar: string;
  name_en: string;
  departments: Department[];
}

export interface University {
  id: string;
  name_ar: string;
  name_en: string;
  website: string;
  type: "public" | "private";
  founded: number;
  country_code: string;
  country_ar: string;
  country_en: string;
  logo?: string;
  colleges: College[];
}

// Helper to find university by name (ar or en)
export const findUniversityByName = (name: string | null | undefined): University | undefined => {
  if (!name) return undefined;
  const lower = name.toLowerCase().trim();
  return allUniversities.find(
    (u) =>
      u.name_ar === name ||
      u.name_en.toLowerCase() === lower ||
      lower.includes(u.name_en.toLowerCase()) ||
      lower.includes(u.name_ar)
  );
};

